import os
import json
from typing import Dict, List, Callable, Optional, Any

from tqdm import tqdm


class Processor:
    def __init__(
        self,
        namespace: str,
        task_name: str,
        sys_prompt_template_path: str,
        user_prompt_template_path: str,
        kwargs_generator: Callable,
        inference_func: Callable,
        input_json_paths: List[str],
        image_filter: Callable = lambda _: True,
        base_folder: str = "",
        output_folder: str = "response",
        random_seed: int = 42,
        sample_rate: float = 1,
        tqdm_position: int = 0,
    ):
        """
        Args:
            namespace: str, "company/model_name"
            task_name: str,
            sys_prompt_template_path: str,  # later will use .format method to fill in the template
            user_prompt_template_path: str,
            kwargs_generator: Callable,
            inference_func: Callable,
            input_json_paths: List[str],
            image_filter: Callable = lambda _: True, # By default the function
            base_folder: str = "",
            output_folder: str = "results",
            random_seed: int = 42,
            sample_rate: float = 1,
            tqdm_position: int = 0

        kwargs_generator is a function which follows the rules below:
        Input_Name: image_path  # It is the image wait for judge.
        Output_Schema:
        {
            # All images should be passed through this list
            "images": [
                image's base64,
                image's base64,
            ],
            # All prompt variables should be passed through this key-value.
            "prompt_param_name_1": "value_1",
            "prompt_param_name_2": "value_2",
            # All params which need record should be passed through this dict.
            "record_params": {
                "images": ["assets/" + ref_image_path, image_path],
                "question": "A:entirely AI-generated; B:partially AI-edited; C:No Forgery; D:uncertain",
            }
        }

        image_filter is a function which follows the rules below:
        Input Name: item(per item in json)
        OutputFormat: Bool(True/False) True to add item to the list, False to skip.

        inference_func is a function which follows the rules below:
        Input Name: messages: List[Dict] # OpenAI-compatible message list
        OutputFormat: Dict # Usually a dict generated by `json.loads(response.choices[0].message.content)`

        """
        self.namespace = namespace
        self.task_name = task_name
        self.company, self.name = namespace.split("/")

        with open(user_prompt_template_path, "r") as f:
            self.user_prompt_template = f.read()
        with open(sys_prompt_template_path, "r") as f:
            self.sys_prompt_template = f.read()
        self.input_json_paths = input_json_paths
        self.base_folder = base_folder
        self.output_base_folder = output_folder
        self.random_seed = random_seed
        self.kwargs_generator = kwargs_generator
        self.inference_func = inference_func
        self.image_filter = image_filter
        self.sample_rate = sample_rate
        self.tqdm_position = tqdm_position

        output_folder_path = os.path.join(
            self.output_base_folder, self.company, self.name
        )

        self.output_json_path = os.path.join(
            output_folder_path, f"{self.task_name}.json"
        )

        self.error_json_path = os.path.join(
            output_folder_path, f"{self.task_name}_error_log.json"
        )
        os.makedirs(output_folder_path, exist_ok=True)
        # print("Output JSON path:", self.output_json_path)
        # print(
        #     "Error log path (If no error, the file will not be created.):",
        #     self.error_json_path,
        # )

        self.image_paths = []
        self.results = []
        self.error_log = []

    def load_processed_images(self) -> List[str]:
        if os.path.exists(self.output_json_path):
            with open(self.output_json_path, "r") as f:
                # print("Load processed images from:", self.output_json_path)
                data = json.load(f)
                self.results = data
            return [item["image_information"]["origin_json_block"]["question_id"] for item in data]
        else:
            return []

    def fetch_images(self) -> List[str]:
        images = []
        for json_path in self.input_json_paths:
            data = []
            with open(json_path, "r") as f:
                data = json.load(f)
            for item in data.get('question', []):
                image_paths = item.get('panel_paths', item.get('figure_path'))
                real_paths = [os.path.join(self.base_folder, p) for p in image_paths]
                images.append({"image_paths": real_paths, "origin_json_block": item})
                # if self.image_filter(item):
                #     images.append({"image_path": real_paths, "origin_json_block": item})

        import random

        if self.sample_rate < 1:
            random.seed(self.random_seed)
            sample_size = int(len(images) * self.sample_rate)
            images = random.sample(images, sample_size)

        processed_ids = self.load_processed_images()
        # images = [
        #     image
        #     for image in images
        #     if image["origin_json_block"] not in processed_images
        # ]
        images = [
            image
            for image in images
            if image["origin_json_block"]["question_id"] not in processed_ids
        ]

        return images

    def build_prompt(self, image_paths, mask_caption, figure_caption, figure_related):
        """
        Use named parameters in the format string.
        Both sys_prompt and user_prompt use the same format string.
        So make sure to use the same format string for both prompts or use different format strings.
        """
        kwargs = self.kwargs_generator(image_paths, mask_caption, figure_caption, figure_related)
        sys_prompt = self.sys_prompt_template
        print('start')
        user_prompt = self.user_prompt_template.format(**kwargs)
        print(user_prompt)
        image_prompt = []
        for image in kwargs.get("images"):
            image_prompt.append(
                {
                    "type": "image_url",
                    "image_url": {"url": image},
                }
            )

        messages = [
            {"role": "system", "content": sys_prompt},
            {
                "role": "user",
                "content": [
                    {"type": "text", "text": user_prompt},
                ] + image_prompt,
            },
        ]

        return messages, kwargs

    def run(self, drop_history=False):
        try:
            self.remove_error_log()
            if drop_history:
                try:
                    os.remove(self.output_json_path)
                    print("History file cleaned.")
                except Exception as _:
                    pass
                    print("No history file. Skipped.")
            self.image_paths = self.fetch_images()

            tqdm_kwargs = {
                "position": self.tqdm_position,
                "desc": f"{self.namespace}/{self.task_name}",
                "leave": True,
            }
            for item in tqdm(self.image_paths, **tqdm_kwargs):
                try:
                    mask_caption = item.get('origin_json_block').get('mask_caption') if item.get('origin_json_block').get('mask_caption') else '[no caption]'
                    figure_caption = item.get('origin_json_block').get('figure_caption') if item.get('origin_json_block').get('figure_caption') else '[empty]'
                    figure_related = item.get('origin_json_block').get('figure_related') if item.get('origin_json_block').get('figure_related') else '[empty]'
                    messages, kwargs = self.build_prompt(item.get("image_paths"), mask_caption, figure_caption, figure_related)
                    result = self.inference_func(messages=messages)
                    self.results.append(
                        {
                            "image_information": item,
                            "result": result,
                            "record_params": kwargs.get("record_params"),
                        }
                    )
                    self.update_json()
                except Exception as e_runtime:
                    kwargs = {}
                    kwargs["record_params"] = {}
                    # Basic error handling
                    kwargs["record_params"]["image_paths"] = item.get("image_paths")
                    kwargs["record_params"]["error_details"] = str(e_runtime)

                    # Json error handling
                    if isinstance(e_runtime, json.JSONDecodeError):
                        with open("decoder_error_log.txt", "a") as f:
                            f.write(
                                f"{self.namespace} - {self.task_name} - {item.get('image_path')}\n{e_runtime.doc}\n"
                            )
                        kwargs["record_params"]["error_type"] = "JsonDecodeError"
                    # Other error handling
                    else:
                        kwargs["record_params"]["error_type"] = "RuntimeError"

                    self.error_log.append(kwargs.get("record_params"))
                    self.update_error_log()

            if len(self.error_log) == 0:
                self.remove_error_log()
                # print("All done.")
        except KeyboardInterrupt as e:
            # Keep json file serialized, otherwise it may be corrupted
            self.update_json()
            # Normal condition, don't raise exception
        except Exception as e:
            # Keep json file serialized, otherwise it may be corrupted
            self.update_json()
            raise e

    def update_json(self):
        with open(self.output_json_path, "w") as f:
            json.dump(self.results, f, indent=4, ensure_ascii=False)

    def update_error_log(self):
        with open(self.error_json_path, "w") as f:
            json.dump(self.error_log, f, indent=4, ensure_ascii=False)

    def remove_error_log(self):
        try:
            os.remove(self.error_json_path)
            # print("Error log file cleaned.")
        except Exception as _:
            pass
            # print("No log file. Skipped.")
